   133→pub fn find_card_in_dir(state_dir: &Path, id: &str) -> Option<PathBuf> {
   134→    let exact = state_dir.join(format!("{}.bop", id));
   135→    if exact.exists() {
   136→        return Some(exact);
   137→    }
   138→    let suffix = format!("-{}.bop", id);
   139→    fs::read_dir(state_dir).ok()?.flatten().find_map(|e| {
   140→        let p = e.path();
   141→        if p.is_dir()
   142→            && p.file_name()
   143→                .and_then(|n| n.to_str())
   144→                .is_some_and(|n| n.ends_with(&suffix))
   145→        {
   146→            Some(p)
   147→        } else {
   148→            None
   149→        }
   150→    })
   151→}
