   193→pub fn quarantine_invalid_pending_card(
   194→    pending_path: &Path,
   195→    failed_dir: &Path,
   196→    reason: &str,
   197→) -> anyhow::Result<()> {
   198→    let name = pending_path
   199→        .file_name()
   200→        .and_then(|n| n.to_str())
   201→        .with_context(|| format!("invalid card path: {}", pending_path.display()))?;
   202→    let failed_path = util::unique_failed_path(failed_dir, name);
   203→    fs::rename(pending_path, &failed_path).with_context(|| {
   204→        format!(
   205→            "failed moving invalid pending card {} to failed/",
   206→            pending_path.display()
   207→        )
   208→    })?;
   209→    fs::create_dir_all(failed_path.join("logs"))?;
   210→    fs::create_dir_all(failed_path.join("output"))?;
   211→    let marker = format!("[{}] dispatcher rejected card: {}\n", Utc::now(), reason);
   212→    util::append_log_line(
   213→        &failed_path.join("logs").join("rejected.log"),
   214→        marker.trim_end(),
   215→    )?;
   216→    let _ = fs::write(failed_path.join("output").join("qa_report.md"), marker);
   217→    quicklook::render_card_thumbnail(&failed_path);
   218→    Ok(())
   219→}
