   138→fn dir_size(path: &Path) -> u64 {
   139→    let mut total = 0u64;
   140→    if let Ok(entries) = fs::read_dir(path) {
   141→        for entry in entries.flatten() {
   142→            let path = entry.path();
   143→            if let Ok(metadata) = fs::metadata(&path) {
   144→                if metadata.is_dir() {
   145→                    total += dir_size(&path);
   146→                } else {
   147→                    total += metadata.len();
   148→                }
   149→            }
   150→        }
   151→    }
   152→    total
   153→}
