    26→pub fn clone_template(src: &Path, dst: &Path) -> anyhow::Result<()> {
    27→    // Ensure destination parent directory exists
    28→    if let Some(parent) = dst.parent() {
    29→        fs::create_dir_all(parent)?;
    30→    }
    31→
    32→    // Prefer APFS clone semantics on macOS (ditto --clone), then cp -c.
    33→    if cfg!(target_os = "macos") {
    34→        let status = StdCommand::new("ditto")
    35→            .arg("--clone")
    36→            .arg(src)
    37→            .arg(dst)
    38→            .status();
    39→        if matches!(status, Ok(s) if s.success()) {
    40→            return Ok(());
    41→        }
    42→
    43→        let status = StdCommand::new("cp")
    44→            .arg("-c") // COW clone on APFS
    45→            .arg("-R") // Recursive
    46→            .arg(src)
    47→            .arg(dst)
    48→            .status();
    49→        if matches!(status, Ok(s) if s.success()) {
    50→            return Ok(());
    51→        }
    52→
    53→        anyhow::bail!(
    54→            "APFS clone copy failed (required on macOS): {} -> {}",
    55→            src.display(),
    56→            dst.display()
    57→        );
    58→    } else {
    59→        // Try Btrfs reflink on Linux
    60→        let status = StdCommand::new("cp")
    61→            .arg("--reflink=auto") // Try COW, fallback to regular copy
    62→            .arg("-r")
    63→            .arg(src)
    64→            .arg(dst)
    65→            .status();
    66→        if matches!(status, Ok(s) if s.success()) {
    67→            return Ok(());
    68→        }
    69→
    70→        // Fallback to regular copy if reflink fails
    71→        let status = StdCommand::new("cp").arg("-r").arg(src).arg(dst).status();
    72→        if matches!(status, Ok(s) if s.success()) {
    73→            return Ok(());
    74→        }
    75→    }
    76→
    77→    // Final fallback to manual copy
    78→    util::copy_dir_all(src, dst)
    79→}
